    int low, high;
    Interval(int low, int high) {
        this.low = low;
        this.high = high;
    }
}

class Node {
    Interval interval;
    int maxHigh;
    Node left, right;

    Node(Interval interval) {
        this.interval = interval;
        this.maxHigh = interval.high;
        this.left = null;
        this.right = null;
    }
}

class IntervalTree {
    private Node root;

    void insert(Interval interval) {
        root = insert(root, interval);
    }

    private Node insert(Node node, Interval interval) {
        if (node == null) {
            return new Node(interval);
        }
        if (interval.low < node.interval.low) {
            node.left = insert(node.left, interval);
        } else {
            node.right = insert(node.right, interval);
        }
        node.maxHigh = Math.max(node.maxHigh, interval.high);
        return node;
    }

    java.util.List<Interval> overlapSearch(Interval interval) {
        java.util.List<Interval> result = new java.util.ArrayList<>();
        overlapSearch(root, interval, result);
        return result;
    }

    private void overlapSearch(Node node, Interval interval, java.util.List<Interval> result) {
        if (node == null) return;
        if (node.interval.low <= interval.high && interval.low <= node.interval.high) {
            result.add(node.interval);
        }
        if (node.left != null && node.left.maxHigh >= interval.low) {
            overlapSearch(node.left, interval, result);
        }
        if (node.right != null && node.maxHigh >= interval.low) {
            overlapSearch(node.right, interval, result);
        }
    }
}

