#include <stdio.h>
#include <stdlib.h>

typedef struct Interval {
    int low, high;
} Interval;

typedef struct Node {
    Interval interval;
    int maxHigh;
    struct Node *left, *right;
} Node;

typedef struct IntervalTree {
    Node* root;
} IntervalTree;

Node* createNode(Interval interval) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->interval = interval;
    node->maxHigh = interval.high;
    node->left = node->right = NULL;
    return node;
}

IntervalTree* createIntervalTree() {
    IntervalTree* tree = (IntervalTree*)malloc(sizeof(IntervalTree));
    tree->root = NULL;
    return tree;
}

Node* insert(Node* node, Interval interval) {
    if (!node) {
        return createNode(interval);
    }
    if (interval.low < node->interval.low) {
        node->left = insert(node->left, interval);
    } else {
        node->right = insert(node->right, interval);
    }
    if (node->maxHigh < interval.high) {
        node->maxHigh = interval.high;
    }
    return node;
}

void insertInterval(IntervalTree* tree, Interval interval) {
    tree->root = insert(tree->root, interval);
}

void overlapSearch(Node* node, Interval interval, Interval** result, int* size) {
    if (!node) return;
    if (node->interval.low <= interval.high && interval.low <= node->interval.high) {
        result[*size] = &node->interval;
        (*size)++;
    }
    if (node->left && node->left->maxHigh >= interval.low) {
        overlapSearch(node->left, interval, result, size);
    }
    if (node->right && node->maxHigh >= interval.low) {
        overlapSearch(node->right, interval, result, size);
    }
}

void freeTree(Node* node) {
    if (!node) return;
    freeTree(node->left);
    freeTree(node->right);
    free(node);
}

int main() {
    IntervalTree* tree = createIntervalTree();
    Interval intervals[] = {{1, 5}, {2, 6}, {3, 7}, {8, 10}};
    for (int i = 0; i < 4; i++) {
        insertInterval(tree, intervals[i]);
    }
    Interval query = {4, 8};
    Interval* result[10];
    int size = 0;
    overlapSearch(tree->root, query, result, &size);
    printf("Overlapping intervals with (4, 8): ");
    for (int i = 0; i < size; i++) {
        printf("(%d, %d) ", result[i]->low, result[i]->high);
    }
    printf("\n");
    freeTree(tree->root);
    free(tree);
    return 0;
}
// Output: Overlapping intervals with (4, 8): (1, 5) (2, 6) (3, 7)

