#include <iostream>
#include <vector>

struct Interval {
    int low, high;
    Interval(int low, int high) : low(low), high(high) {}
};

class Node {
public:
    Interval interval;
    int maxHigh;
    Node *left, *right;

    Node(Interval interval) : interval(interval), maxHigh(interval.high), left(nullptr), right(nullptr) {}
};

class IntervalTree {
private:
    Node* root = nullptr;

    Node* insert(Node* node, Interval interval) {
        if (!node) {
            return new Node(interval);
        }
        if (interval.low < node->interval.low) {
            node->left = insert(node->left, interval);
        } else {
            node->right = insert(node->right, interval);
        }
        node->maxHigh = std::max(node->maxHigh, interval.high);
        return node;
    }

    void overlapSearch(Node* node, Interval interval, std::vector<Interval>& result) {
        if (!node) return;
        if (node->interval.low <= interval.high && interval.low <= node->interval.high) {
            result.push_back(node->interval);
        }
        if (node->left && node->left->maxHigh >= interval.low) {
            overlapSearch(node->left, interval, result);
        }
        if (node->right && node->maxHigh >= interval.low) {
            overlapSearch(node->right, interval, result);
        }
    }

    void freeTree(Node* node) {
        if (!node) return;
        freeTree(node->left);
        freeTree(node->right);
        delete node;
    }

public:
    void insert(Interval interval) {
        root = insert(root, interval);
    }

    std::vector<Interval> overlapSearch(Interval interval) {
        std::vector<Interval> result;
        overlapSearch(root, interval, result);
        return result;
    }

    ~IntervalTree() {
        freeTree(root);
    }
};

int main() {
    IntervalTree tree;
    std::vector<Interval> intervals = {{1, 5}, {2, 6}, {3, 7}, {8, 10}};
    for (const auto& interval : intervals) {
        tree.insert(interval);
    }
    auto overlaps = tree.overlapSearch(Interval(4, 8));
    std::cout << "Overlapping intervals with (4, 8): ";
    for (const auto& i : overlaps) {
        std::cout << "(" << i.low << ", " << i.high << ") ";
    }
    std::cout << "\n";
    return 0;
}
// Output: Overlapping intervals with (4, 8): (1, 5) (2, 6) (3, 7)

